.darma-loader-uiverse-powershell-download-panel {
  width: 290px;
  overflow: hidden;
  border: 1px solid #1f2937;
  border-radius: 7px 7px 4px 4px;
  background: #050505;
  color: #e5e7eb;
  font-family: Consolas, "Courier New", monospace;
  box-shadow: 0 18px 40px rgba(15, 23, 42, 0.28);
}

.darma-loader-uiverse-powershell-download-panel__header-bar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 6px 8px;
  background: #f8fafc;
  color: #0f172a;
}

.darma-loader-uiverse-powershell-download-panel__title {
  display: flex;
  align-items: center;
  gap: 6px;
  margin: 0;
  font-family: "Segoe UI", Arial, sans-serif;
  font-size: 12px;
  font-weight: 600;
}

.darma-loader-uiverse-powershell-download-panel__icon {
  display: inline-grid;
  place-items: center;
  width: 22px;
  height: 18px;
  border-radius: 4px;
  background: var(--loader-color, #0277bd);
  color: #ffffff;
  font-size: 10px;
  font-weight: 800;
}

.darma-loader-uiverse-powershell-download-panel__controls {
  display: flex;
  align-items: center;
  gap: 11px;
  font-size: 11px;
  line-height: 1;
}

.darma-loader-uiverse-powershell-download-panel__terminal {
  min-height: 174px;
  padding: 10px 12px 12px;
  font-size: 12px;
  line-height: 1.45;
}

.darma-loader-uiverse-powershell-download-panel__terminal p {
  margin: 0 0 5px;
}

.darma-loader-uiverse-powershell-download-panel__prompt {
  color: #93c5fd;
}

.darma-loader-uiverse-powershell-download-panel__download-row {
  display: flex;
  justify-content: space-between;
  margin: 7px 0 4px;
  color: #bbf7d0;
}

.darma-loader-uiverse-powershell-download-panel__percent {
  color: var(--loader-secondary-color, #22c55e);
  font-weight: 700;
}

.darma-loader-uiverse-powershell-download-panel__track {
  height: 10px;
  overflow: hidden;
  border: 1px solid #166534;
  background: #052e16;
  margin-bottom: 9px;
}

.darma-loader-uiverse-powershell-download-panel__bar {
  display: block;
  width: 45%;
  height: 100%;
  background: linear-gradient(90deg, #16a34a, #86efac, #16a34a);
  animation: darma-loader-uiverse-powershell-download-panel-download 1.4s ease-in-out infinite;
}

.darma-loader-uiverse-powershell-download-panel__running {
  color: #facc15;
}

.darma-loader-uiverse-powershell-download-panel__spinner {
  display: inline-block;
  width: 1ch;
  color: #ffffff;
  animation: darma-loader-uiverse-powershell-download-panel-spin 0.8s steps(4) infinite;
}

@keyframes darma-loader-uiverse-powershell-download-panel-download {
  0% {
    transform: translateX(-100%);
  }
  55% {
    transform: translateX(35%);
  }
  100% {
    transform: translateX(230%);
  }
}

@keyframes darma-loader-uiverse-powershell-download-panel-spin {
  0% {
    transform: rotate(0deg);
  }
  25% {
    transform: rotate(90deg);
  }
  50% {
    transform: rotate(180deg);
  }
  75% {
    transform: rotate(270deg);
  }
  100% {
    transform: rotate(360deg);
  }
}

